class Solution(object):
    def minimumSum(self, nums):
        n = len(nums)
        best = float('inf')
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    if nums[i] < nums[j] and nums[k] < nums[j]:
                        best = min(best, nums[i] + nums[j] + nums[k])
        return best if best < float('inf') else -1
